const { useState, useEffect, useRef } = React;
const CHAPTERS = [{ "id": 1, "level": "A1", "title": "DER PILOT", "theme": "MECHA / ELEKTRONIK", "focus": { "title": "sein + der/die/das", "en": "German nouns have a gender: der (masc.), die (fem.), das (neuter). Learn every noun WITH its article. 'ist/sind/bin' are forms of 'sein' (to be)." }, "paragraphs": [["Das ist meine Maschine.", "Sie hei\xDFt ERIS-7.", "Sie ist zw\xF6lf Meter gro\xDF und grau."], ["Ich bin der Pilot.", "Ich pr\xFCfe das System.", "Der Reaktor ist hei\xDF.", "Das ist ein Problem."], ["Ein Sensor blinkt rot.", "Der Sensor misst die Temperatur.", "Die Temperatur ist zu hoch."], ["Ich \xF6ffne das Panel.", "Ich sehe die Platine.", "Ein Kabel ist locker.", "Das ist der Fehler."], ["Ich verbinde das Kabel.", "Der Sensor blinkt gr\xFCn.", "Das System ist stabil.", "Die Maschine ist bereit."], ["Die Stadt brennt.", "Der Feind wartet.", "Der Kampf beginnt."]], "questions": [{ "text": "Was ist der Fehler?", "options": [{ "t": "Ein Kabel ist locker.", "ok": true }, { "t": "Der Pilot ist m\xFCde.", "ok": false }, { "t": "Die Maschine ist zu klein.", "ok": false }] }, { "text": "Was misst der Sensor?", "options": [{ "t": "Die Spannung.", "ok": false }, { "t": "Die Temperatur.", "ok": true }, { "t": "Das Licht.", "ok": false }] }] }, { "id": 2, "level": "A1", "title": "DER MORGEN", "theme": "ALLTAG / ROUTINE", "focus": { "title": "Verben im Pr\xE4sens + um \u2026 Uhr", "en": "Present tense endings: ich trinke, er trinkt, wir trinken. Time uses 'um': um sechs Uhr = at six o'clock. Some verbs split: 'aufstehen' \u2192 'Ich stehe auf.'" }, "paragraphs": [["Es ist sechs Uhr.", "Ich stehe auf.", "Der Hangar ist kalt und still."], ["Ich trinke Kaffee.", "Ich esse Brot mit K\xE4se.", "Das Fr\xFChst\xFCck ist einfach."], ["Dann gehe ich zur Maschine.", "ERIS-7 schl\xE4ft.", "Die Lampen sind aus."], ["Ich starte den Computer.", "Das Log ist leer.", "Keine Fehler.", "Gut."], ["Um sieben Uhr kommt der Techniker.", "Er hei\xDFt Bruno.", "Er bringt Werkzeug."], ["Wir arbeiten zusammen.", "Der Tag beginnt."]], "questions": [{ "text": "Wann steht der Pilot auf?", "options": [{ "t": "Um sechs Uhr.", "ok": true }, { "t": "Um sieben Uhr.", "ok": false }, { "t": "Um zw\xF6lf Uhr.", "ok": false }] }, { "text": "Was bringt Bruno?", "options": [{ "t": "Kaffee.", "ok": false }, { "t": "Werkzeug.", "ok": true }, { "t": "Brot.", "ok": false }] }] }, { "id": 3, "level": "A1", "title": "DIE STADT", "theme": "STADT / ESSEN", "focus": { "title": "es gibt + Akkusativ", "en": "'Es gibt' (there is / there are) always takes Akkusativ: Es gibt einen Markt (not 'ein Markt'). Masculine 'ein' \u2192 'einen' in Akkusativ; feminine and neuter don't change." }, "paragraphs": [["Die Stadt hei\xDFt Vesta.", "Sie liegt im Norden.", "Hier gibt es viele Fabriken."], ["Es gibt auch einen Markt.", "Dort kaufe ich Fleisch und Kartoffeln."], ["Zu Hause habe ich eine Hei\xDFluftfritteuse.", "Ich koche das Fleisch zwanzig Minuten.", "Es ist schnell und gut."], ["Am Abend sehe ich die Mauern der Stadt.", "Sie sind hoch und grau.", "Hinter den Mauern liegt die Zone."], ["Niemand geht in die Zone.", "Dort wohnen die Feinde.", "Wir nennen sie: die Geister."]], "questions": [{ "text": "Was kauft der Pilot auf dem Markt?", "options": [{ "t": "Brot und K\xE4se.", "ok": false }, { "t": "Fleisch und Kartoffeln.", "ok": true }, { "t": "Werkzeug.", "ok": false }] }, { "text": "Wer wohnt in der Zone?", "options": [{ "t": "Die Geister.", "ok": true }, { "t": "Die Techniker.", "ok": false }, { "t": "Niemand.", "ok": false }] }] }, { "id": 4, "level": "A1", "title": "DER TECHNIKER", "theme": "WERKSTATT / TECHNIK", "focus": { "title": "Akkusativ: einen / eine / ein", "en": "Direct objects take Akkusativ. Only masculine changes: einen Hammer, einen Stecker. Feminine (eine Zange) and neuter (ein Kabel) stay the same." }, "paragraphs": [["Bruno \xF6ffnet die Maschine.", "Er hat viele Werkzeuge: einen Hammer, eine Zange, einen Schraubenzieher."], ["Er findet ein Problem.", "Zwei Kabel sind alt.", "Ein Stecker ist schwarz.", "Das riecht verbrannt."], ["\xBBWir brauchen neue Teile\xAB, sagt Bruno.", "\xBBOhne Teile fliegt ERIS nicht.\xAB"], ["Ich frage: \xBBWie lange dauert das?\xAB", "Bruno sagt: \xBBZwei Tage.", "Vielleicht drei.\xAB"], ["Zwei Tage sind lang.", "Die Geister warten nicht."]], "questions": [{ "text": "Wie riecht der Stecker?", "options": [{ "t": "Verbrannt.", "ok": true }, { "t": "Neu.", "ok": false }, { "t": "Gut.", "ok": false }] }, { "text": "Wie lange dauert die Reparatur?", "options": [{ "t": "F\xFCnf Minuten.", "ok": false }, { "t": "Zwei Wochen.", "ok": false }, { "t": "Zwei Tage, vielleicht drei.", "ok": true }] }] }, { "id": 5, "level": "A1", "title": "DAS ESSEN", "theme": "IMBISS / BESTELLEN", "focus": { "title": "ohne + Akkusativ, m\xF6chten", "en": "'ohne' (without) always takes Akkusativ: ohne So\xDFe, ohne Zwiebeln. 'M\xF6chten Sie \u2026?' is the polite way to ask 'Would you like \u2026?' \u2014 you will hear it in every shop." }, "paragraphs": [["Am Freitag gehe ich in die Stadt.", "Ich habe Hunger.", "Es gibt einen Imbiss am Markt."], ["Ich sage: \xBBEinen Burger mit H\xE4hnchen, bitte.", "Aber ohne So\xDFe und ohne Zwiebeln.\xAB"], ["Der Mann fragt: \xBBM\xF6chten Sie Pommes?\xAB", "Ich sage: \xBBJa, eine kleine Portion.\xAB"], ["Das Essen kostet acht Euro.", "Ich bezahle und warte f\xFCnf Minuten."], ["Der Burger ist hei\xDF und gut.", "Ohne So\xDFe schmeckt er besser.", "Das ist meine Meinung."]], "questions": [{ "text": "Was bestellt der Pilot?", "options": [{ "t": "Einen Burger ohne So\xDFe und ohne Zwiebeln.", "ok": true }, { "t": "Eine Pizza mit K\xE4se.", "ok": false }, { "t": "Nur Pommes.", "ok": false }] }, { "text": "Was kostet das Essen?", "options": [{ "t": "F\xFCnf Euro.", "ok": false }, { "t": "Acht Euro.", "ok": true }, { "t": "Zw\xF6lf Euro.", "ok": false }] }] }, { "id": 6, "level": "A1", "title": "DER BEFEHL", "theme": "MILIT\xC4R / MODALVERBEN", "focus": { "title": "Modalverben: m\xFCssen, k\xF6nnen, sollen, wollen", "en": "Modal verb sits in position 2, the main verb goes to the END as infinitive: 'Du musst heute fliegen.' Negation: 'Du musst nicht k\xE4mpfen' = you don't have to fight." }, "paragraphs": [["Um Mitternacht klingelt das Telefon.", "Der Kommandant spricht: \xBBDie Geister kommen.", "Du musst fliegen.\xAB"], ["Ich sage: \xBBDie Maschine ist nicht fertig.", "Wir k\xF6nnen nicht k\xE4mpfen.\xAB"], ["\xBBDu musst nicht k\xE4mpfen\xAB, sagt er.", "\xBBDu sollst nur beobachten.", "Flieg hoch und bleib ruhig.\xAB"], ["Bruno arbeitet schnell.", "Nach einer Stunde sagt er: \xBBDie Kabel sind neu.", "Du kannst starten.\xAB"], ["Ich will nicht fliegen.", "Aber ich muss.", "Das ist der Befehl."]], "questions": [{ "text": "Was soll der Pilot machen?", "options": [{ "t": "Er soll k\xE4mpfen.", "ok": false }, { "t": "Er soll nur beobachten.", "ok": true }, { "t": "Er soll schlafen.", "ok": false }] }, { "text": "Wann klingelt das Telefon?", "options": [{ "t": "Um Mitternacht.", "ok": true }, { "t": "Am Morgen.", "ok": false }, { "t": "Um sieben Uhr.", "ok": false }] }] }, { "id": 7, "level": "A1", "title": "DIE NACHT", "theme": "MISSION / PERFEKT", "focus": { "title": "Perfekt: haben oder sein?", "en": "Past tense in speech = Perfekt: haben/sein + participle at the end. Movement/change verbs take SEIN: ich bin geflogen. Most others take HABEN: ich habe gesehen." }, "paragraphs": [["Ich bin drei Stunden geflogen.", "Die Zone war dunkel und still."], ["Dann habe ich ein Licht gesehen.", "Es war kein Geist.", "Es war ein Mensch \u2014 ein M\xE4dchen mit einer Lampe."], ["Ich habe sie fotografiert und bin zur\xFCckgeflogen.", "Der Kommandant hat das Foto lange angesehen."], ["\xBBDas ist unm\xF6glich\xAB, hat er gesagt.", "\xBBIn der Zone wohnen keine Menschen.\xAB"], ["Aber das Foto l\xFCgt nicht.", "Jemand lebt dort.", "Und wir wissen nicht, wer."]], "questions": [{ "text": "Was hat der Pilot in der Zone gesehen?", "options": [{ "t": "Einen Geist.", "ok": false }, { "t": "Ein M\xE4dchen mit einer Lampe.", "ok": true }, { "t": "Nichts.", "ok": false }] }, { "text": "Wie lange ist der Pilot geflogen?", "options": [{ "t": "Eine Stunde.", "ok": false }, { "t": "Drei Stunden.", "ok": true }, { "t": "Die ganze Nacht.", "ok": false }] }] }, { "id": 8, "level": "A2", "title": "DIE FESTUNG", "theme": "MITTELALTER / TAKTIK", "focus": { "title": "Adjektive nach sein + aber", "en": "After 'sein' adjectives take no ending: Die Mauern sind alt. 'aber' connects two contrasting ideas without changing word order: alt, aber stark." }, "paragraphs": [["Der Winter kommt.", "Unsere Festung liegt am Fluss.", "Die Mauern sind alt, aber stark."], ["Ich z\xE4hle die Soldaten: vierzig Mann.", "Wir haben wenig Pfeile und wenig Brot."], ["Der Feind hat zweihundert Mann.", "Er hat auch eine Belagerungsmaschine.", "Sie ist aus Holz."], ["Aber wir haben einen Plan.", "Das Tor bleibt offen.", "Der Feind sieht das Tor und l\xE4uft in die Falle."], ["Hinter dem Tor wartet \xD6l.", "Es ist hei\xDF.", "Der Hauptmann hebt die Hand.", "Wir warten."]], "questions": [{ "text": "Was ist der Plan?", "options": [{ "t": "Wir verlassen die Festung.", "ok": false }, { "t": "Das offene Tor ist eine Falle.", "ok": true }, { "t": "Wir kaufen mehr Brot.", "ok": false }] }, { "text": "Wie viele Soldaten hat die Festung?", "options": [{ "t": "Vierzig.", "ok": true }, { "t": "Zweihundert.", "ok": false }, { "t": "Zehn.", "ok": false }] }] }, { "id": 9, "level": "A2", "title": "DER BOTE", "theme": "MITTELALTER / PR\xC4TERITUM", "focus": { "title": "Pr\xE4teritum (war, hatte) + weil", "en": "In stories, 'sein' and 'haben' use simple past: war, hatte. 'weil' (because) kicks the verb to the END of the clause: \u2026, weil dort Krieg ist." }, "paragraphs": [["Vor der Schlacht kam ein Bote.", "Er war jung und hatte Angst."], ["Er brachte einen Brief vom K\xF6nig.", "Der Hauptmann las den Brief langsam."], ["\xBBEs gibt keine Hilfe\xAB, sagte er.", "\xBBDer K\xF6nig braucht seine Soldaten im S\xFCden, weil dort Krieg ist.\xAB"], ["Die M\xE4nner waren still.", "Vierzig gegen zweihundert \u2014 ohne Hilfe."], ["Aber der Hauptmann l\xE4chelte.", "\xBBGut\xAB, sagte er.", "\xBBDann gewinnen wir allein.\xAB"]], "questions": [{ "text": "Warum gibt es keine Hilfe?", "options": [{ "t": "Weil der K\xF6nig die Soldaten im S\xFCden braucht.", "ok": true }, { "t": "Weil der Bote den Brief verloren hat.", "ok": false }, { "t": "Weil der Winter kommt.", "ok": false }] }, { "text": "Wie war der Bote?", "options": [{ "t": "Alt und stark.", "ok": false }, { "t": "Jung, und er hatte Angst.", "ok": true }, { "t": "Laut und froh.", "ok": false }] }] }, { "id": 10, "level": "A2", "title": "DAS AMT", "theme": "B\xDCROKRATIE / FORMULARE", "focus": { "title": "Sie-Imperativ + Dativ (mir, Ihnen)", "en": "Polite commands: 'F\xFCllen Sie das aus.' (verb first + Sie). 'geben' takes Dativ for the receiver: Sie gibt MIR ein Formular. You will hear 'Haben Sie einen Termin?' in every German office." }, "paragraphs": [["Zur\xFCck in Vesta: Ich brauche eine neue Lizenz f\xFCr die Maschine.", "Ohne Lizenz darf ich nicht fliegen."], ["Ich gehe zum Amt.", "Die Frau am Schalter gibt mir ein Formular und sagt: \xBBF\xFCllen Sie das bitte aus.\xAB"], ["Das Formular hat vier Seiten.", "Ich brauche meinen Pass, eine Bescheinigung und ein Foto."], ["\xBBHaben Sie einen Termin?\xAB, fragt die Frau.", "Ich sage: \xBBNein.", "Kann ich heute einen Termin machen?\xAB"], ["\xBBDer n\xE4chste Termin ist in drei Wochen\xAB, sagt sie.", "Ich bleibe ruhig.", "Das Amt ist st\xE4rker als jeder Feind."]], "questions": [{ "text": "Was braucht der Pilot f\xFCr das Formular?", "options": [{ "t": "Nur ein Foto.", "ok": false }, { "t": "Pass, Bescheinigung und Foto.", "ok": true }, { "t": "Geld und Werkzeug.", "ok": false }] }, { "text": "Wann ist der n\xE4chste Termin?", "options": [{ "t": "Heute.", "ok": false }, { "t": "In drei Wochen.", "ok": true }, { "t": "Morgen.", "ok": false }] }] }, { "id": 11, "level": "A2", "title": "DIE WERKSTATT", "theme": "ELEKTRONIK / VERGLEICHE", "focus": { "title": "Komparativ + als", "en": "Comparative = adjective + er: stark \u2192 st\xE4rker, alt \u2192 \xE4lter (often with umlaut). Compare with 'als': besser als, l\xE4nger als. 'deshalb' (therefore) links cause and result." }, "paragraphs": [["Bruno zeigt mir die Werkstatt.", "Auf dem Tisch liegen Widerst\xE4nde, Kondensatoren und eine gro\xDFe Platine."], ["\xBBDieser Widerstand ist zu schwach\xAB, sagt er.", "\xBBWir brauchen einen st\xE4rkeren.", "Und dieser Kondensator ist \xE4lter als du.\xAB"], ["Er misst die Spannung: zw\xF6lf Volt.", "Der Strom ist zu hoch, deshalb wird das Kabel warm."], ["Ich lerne viel: Ein kurzes Kabel ist besser als ein langes.", "Ein kaltes System lebt l\xE4nger als ein hei\xDFes."], ["\xBBElektronik ist einfach\xAB, sagt Bruno.", "\xBBMenschen sind komplizierter.\xAB"]], "questions": [{ "text": "Warum wird das Kabel warm?", "options": [{ "t": "Weil der Strom zu hoch ist.", "ok": true }, { "t": "Weil die Sonne scheint.", "ok": false }, { "t": "Weil das Kabel neu ist.", "ok": false }] }, { "text": "Was ist besser?", "options": [{ "t": "Ein langes Kabel.", "ok": false }, { "t": "Ein kurzes Kabel.", "ok": true }, { "t": "Ein warmes Kabel.", "ok": false }] }] }, { "id": 12, "level": "A2", "title": "DAS LOGBUCH", "theme": "MIKROKLIMA / TECHNIK", "focus": { "title": "Zahlen + Messwerte lesen", "en": "Technical German states values with 'liegt bei / betr\xE4gt': Die Luftfeuchtigkeit liegt bei 82 Prozent. 'kein/keine' negates nouns: keinen Strom = no power." }, "paragraphs": [["Station M-5, Tag 112.", "Ich kontrolliere das Klimasystem jeden Morgen."], ["Heute zeigt das Log einen Fehler: Die Luftfeuchtigkeit im Labor liegt bei 82 Prozent.", "Normal sind 45 Prozent."], ["Ein L\xFCfter l\xE4uft nicht.", "Der Motor bekommt keinen Strom.", "Ich messe die Spannung: null Volt."], ["Die Sicherung ist kaputt.", "Ich habe eine neue Sicherung.", "Nach zehn Minuten l\xE4uft der L\xFCfter wieder."], ["Die Werte sinken langsam.", "Das System ist wieder normal.", "Ich schreibe alles ins Logbuch."]], "questions": [{ "text": "Warum l\xE4uft der L\xFCfter nicht?", "options": [{ "t": "Das Labor ist zu kalt.", "ok": false }, { "t": "Das Logbuch fehlt.", "ok": false }, { "t": "Die Sicherung ist kaputt.", "ok": true }] }, { "text": "Wie hoch ist die Luftfeuchtigkeit heute?", "options": [{ "t": "45 Prozent.", "ok": false }, { "t": "82 Prozent.", "ok": true }, { "t": "112 Prozent.", "ok": false }] }] }, { "id": 13, "level": "A2", "title": "DER VERDACHT", "theme": "STORY / WENN-S\xC4TZE", "focus": { "title": "wenn-S\xE4tze", "en": "'wenn' (if/when) sends the verb to the end: Wenn ich es melde, schickt er Soldaten. If the wenn-clause comes first, the main clause starts with the verb." }, "paragraphs": [["Ich habe das M\xE4dchen wieder gesehen \u2014 diesmal am Markt in Vesta.", "Wenn das stimmt, kann sie durch die Mauer gehen."], ["Ich bin ihr gefolgt.", "Sie hat Brot gekauft und hat mit niemandem gesprochen."], ["An der Mauer ist sie stehen geblieben.", "Dann war sie weg.", "Einfach weg."], ["Ich habe dem Kommandanten nichts gesagt.", "Wenn ich es melde, schickt er Soldaten."], ["Vielleicht ist sie kein Geist.", "Vielleicht ist sie der Schl\xFCssel."]], "questions": [{ "text": "Wo hat der Pilot das M\xE4dchen gesehen?", "options": [{ "t": "In der Zone.", "ok": false }, { "t": "Am Markt in Vesta.", "ok": true }, { "t": "Im Hangar.", "ok": false }] }, { "text": "Warum sagt der Pilot dem Kommandanten nichts?", "options": [{ "t": "Weil der Kommandant sonst Soldaten schickt.", "ok": true }, { "t": "Weil er das M\xE4dchen nicht gesehen hat.", "ok": false }, { "t": "Weil das Telefon kaputt ist.", "ok": false }] }] }, { "id": 14, "level": "B1", "title": "DER BRIEF VOM AMT", "theme": "AMTSDEUTSCH / PASSIV", "focus": { "title": "Passiv + \u201Eist einzureichen\u201C", "en": "Official German loves passive: wurde gepr\xFCft (was checked), wird abgelehnt (will be rejected). 'ist einzureichen' = must be submitted \u2014 a passive obligation you will see in every official letter." }, "paragraphs": [["Ein Brief liegt im Briefkasten.", "Ich \xF6ffne ihn langsam."], ["\xBBSehr geehrter Herr, Ihr Antrag vom 12. M\xE4rz wurde gepr\xFCft.", "Folgende Unterlagen fehlen: eine g\xFCltige Bescheinigung \xFCber die technische Kontrolle der Maschine."], ["Die Bescheinigung ist innerhalb von 14 Tagen einzureichen.", "Andernfalls wird der Antrag abgelehnt."], ["Bitte beachten Sie: Ohne g\xFCltige Lizenz ist der Betrieb der Maschine verboten.", "Bei Fragen wenden Sie sich an das B\xFCrgerb\xFCro, Zimmer 214.\xAB"], ["Ich lese den Brief dreimal.", "Amtsdeutsch ist eine eigene Sprache: kalt, pr\xE4zise, ohne Gnade.", "Aber ich verstehe die Regel: Wer die Formulare beherrscht, beherrscht die Stadt."]], "questions": [{ "text": "Was fehlt dem Antrag?", "options": [{ "t": "Eine g\xFCltige Bescheinigung \xFCber die technische Kontrolle.", "ok": true }, { "t": "Ein Foto des Piloten.", "ok": false }, { "t": "Die Unterschrift des Kommandanten.", "ok": false }] }, { "text": "Was passiert, wenn die Bescheinigung nicht kommt?", "options": [{ "t": "Nichts.", "ok": false }, { "t": "Der Antrag wird abgelehnt.", "ok": true }, { "t": "Das Amt ruft an.", "ok": false }] }] }, { "id": 15, "level": "B1", "title": "DAS DATENBLATT", "theme": "ELEKTRONIK / TECHNIK", "focus": { "title": "Relativs\xE4tze + Partizip als Adjektiv", "en": "Relative clauses describe a noun and push the verb to the end: der Sensor, der die Temperatur misst. Participles work as adjectives: ein besch\xE4digter Sensor = a damaged sensor." }, "paragraphs": [["Bruno gibt mir ein Datenblatt.", "\xBBTemperatursensor TX-90.", "Lies das, dann verstehst du die Maschine besser.\xAB"], ["Ich lese: Der Sensor misst Temperaturen von minus 40 bis plus 125 Grad.", "Die Genauigkeit betr\xE4gt 0,5 Grad.", "Die Versorgungsspannung liegt zwischen 3 und 5 Volt."], ["Wichtig ist die Warnung: Wenn die Spannung 6 Volt \xFCberschreitet, wird der Sensor besch\xE4digt.", "Ein besch\xE4digter Sensor liefert falsche Werte \u2014 und falsche Werte sind gef\xE4hrlicher als keine Werte."], ["Jetzt verstehe ich den Fehler von Kapitel eins: Das lockere Kabel hat die Verbindung unterbrochen, und der Sensor hat Unsinn gemeldet."], ["Ein System ist nur so ehrlich wie sein schw\xE4chster Sensor."]], "questions": [{ "text": "Was passiert, wenn die Spannung 6 Volt \xFCberschreitet?", "options": [{ "t": "Der Sensor wird besch\xE4digt.", "ok": true }, { "t": "Der Sensor wird genauer.", "ok": false }, { "t": "Nichts passiert.", "ok": false }] }, { "text": "Warum sind falsche Werte gef\xE4hrlich?", "options": [{ "t": "Weil sie gef\xE4hrlicher sind als keine Werte.", "ok": true }, { "t": "Weil sie zu klein sind.", "ok": false }, { "t": "Weil das Datenblatt fehlt.", "ok": false }] }] }, { "id": 16, "level": "B1", "title": "DIE BELAGERUNG", "theme": "MITTELALTER / ERZ\xC4HLUNG", "focus": { "title": "Pr\xE4teritum starker Verben + dass", "en": "Written narration uses Pr\xE4teritum: griff an (attacked), floss (flowed), fiel (fell), floh (fled). 'dass' (that) introduces reported thoughts and sends the verb to the end." }, "paragraphs": [["Der Feind griff am Morgen an.", "Die Belagerungsmaschine rollte langsam zum Tor, das offen stand."], ["Die Soldaten des Feindes lachten, weil sie dachten, dass wir dumm waren.", "Sie liefen durch das Tor \u2014 direkt in die Falle."], ["Das hei\xDFe \xD6l floss von den Mauern.", "Wer nicht fiel, floh.", "Die Belagerungsmaschine brannte bis zum Abend."], ["Der Hauptmann sagte sp\xE4ter: \xBBEine offene T\xFCr macht mehr Angst als eine geschlossene \u2014 wenn der Gegner denkt.\xAB"], ["Wir verloren drei M\xE4nner.", "Der Feind verlor den Glauben.", "Das war wichtiger."]], "questions": [{ "text": "Warum lachten die Soldaten des Feindes?", "options": [{ "t": "Weil sie dachten, dass die Verteidiger dumm waren.", "ok": true }, { "t": "Weil das Wetter gut war.", "ok": false }, { "t": "Weil sie gewonnen hatten.", "ok": false }] }, { "text": "Was verlor der Feind?", "options": [{ "t": "Drei M\xE4nner.", "ok": false }, { "t": "Den Glauben.", "ok": true }, { "t": "Das \xD6l.", "ok": false }] }] }, { "id": 17, "level": "B1", "title": "DAS GESPR\xC4CH", "theme": "BEWERBUNG / KONJUNKTIV", "focus": { "title": "Konjunktiv II: w\xE4re, h\xE4tte, k\xF6nnte", "en": "Konjunktiv II = would/could/had: w\xE4re (would be), h\xE4tte (would have), k\xF6nnte (could). Essential for politeness and job interviews: Ich h\xE4tte gern diese Stelle. K\xF6nnten Sie \u2026?" }, "paragraphs": [["Nach dem Krieg suchte ich Arbeit.", "Die Firma Vesta-Technik suchte einen Techniker f\xFCr Klimasysteme."], ["Im Gespr\xE4ch fragte die Chefin: \xBBWarum sollten wir Sie nehmen?\xAB", "Ich antwortete: \xBBIch habe drei Jahre lang eine Kampfmaschine am Leben gehalten.", "Ihr Klimasystem w\xE4re dagegen Urlaub.\xAB"], ["Sie l\xE4chelte.", "\xBBUnd wenn ein Kunde unfreundlich w\xE4re?\xAB", "\u2014 \xBBDann bliebe ich freundlich.", "Ich h\xE4tte gern diese Stelle, aber ich brauche keinen Krieg mehr.\xAB"], ["\xBBK\xF6nnten Sie am Montag anfangen?\xAB, fragte sie."], ["Ich konnte."]], "questions": [{ "text": "Was f\xFCr einen Techniker sucht die Firma?", "options": [{ "t": "Einen Techniker f\xFCr Klimasysteme.", "ok": true }, { "t": "Einen Piloten.", "ok": false }, { "t": "Einen Koch.", "ok": false }] }, { "text": "Was w\xFCrde der Pilot machen, wenn ein Kunde unfreundlich w\xE4re?", "options": [{ "t": "Er bliebe freundlich.", "ok": true }, { "t": "Er w\xFCrde gehen.", "ok": false }, { "t": "Er w\xFCrde k\xE4mpfen.", "ok": false }] }] }, { "id": 18, "level": "B2", "title": "DER FEHLERBERICHT", "theme": "TECHNIK / NOMINALSTIL", "focus": { "title": "Nominalstil + Passiv Perfekt", "en": "Professional reports turn verbs into nouns: \xFCberhitzen \u2192 die \xDCberhitzung, unterbrechen \u2192 die Unterbrechung. Passive perfect: wurde festgestellt (was identified), konnte verhindert werden (could be prevented)." }, "paragraphs": [["Fehlerbericht Nr. 44, System ERIS-7.", "Verfasser: B. Weber, Techniker."], ["Zusammenfassung: Bei der Routinekontrolle wurde eine \xDCberhitzung des Reaktors festgestellt.", "Als Ursache wurde ein lockerer Steckverbinder identifiziert, der zu einer Unterbrechung der Sensorleitung f\xFChrte."], ["Infolge der fehlenden Temperaturdaten schaltete die Steuerung nicht in den K\xFChlmodus.", "Eine Besch\xE4digung des Reaktorkerns konnte durch das rechtzeitige Eingreifen des Piloten verhindert werden."], ["Ma\xDFnahmen: S\xE4mtliche Steckverbinder wurden ersetzt.", "Zus\xE4tzlich wurde eine redundante Messleitung installiert.", "Eine Wiederholung des Fehlers gilt als unwahrscheinlich."], ["Anmerkung des Verfassers: Maschinen versagen selten ohne Grund.", "Meistens haben Menschen den Grund montiert."]], "questions": [{ "text": "Was wurde als Ursache identifiziert?", "options": [{ "t": "Ein lockerer Steckverbinder.", "ok": true }, { "t": "Ein alter Reaktor.", "ok": false }, { "t": "Ein Fehler des Piloten.", "ok": false }] }, { "text": "Warum schaltete die Steuerung nicht in den K\xFChlmodus?", "options": [{ "t": "Weil die Temperaturdaten fehlten.", "ok": true }, { "t": "Weil der Strom ausfiel.", "ok": false }, { "t": "Weil der Modus verboten war.", "ok": false }] }] }, { "id": 19, "level": "B2", "title": "DER WIDERSPRUCH", "theme": "B\xDCROKRATIE / FORMELL", "focus": { "title": "Formelle Briefe: hiermit, fristgerecht, stattgeben", "en": "Objection-letter formulas: hiermit lege ich Widerspruch ein (I hereby object), fristgerecht (within the deadline), einem Antrag stattgeben (to grant an application). These exact phrases open doors in Germany." }, "paragraphs": [["Das Amt lehnte meinen Antrag ab \u2014 wegen eines fehlenden Stempels.", "Ich schrieb einen Widerspruch:"], ["\xBBSehr geehrte Damen und Herren, hiermit lege ich Widerspruch gegen Ihren Bescheid vom 3. Mai ein.", "Die geforderte Bescheinigung wurde fristgerecht eingereicht, was durch die beigef\xFCgte Kopie belegt wird."], ["Ich bitte Sie daher, den Bescheid zu \xFCberpr\xFCfen und meinem Antrag stattzugeben.", "Sollte dies nicht m\xF6glich sein, bitte ich um eine schriftliche Begr\xFCndung.", "Mit freundlichen Gr\xFC\xDFen.\xAB"], ["Zwei Wochen sp\xE4ter kam die Antwort: Dem Widerspruch wurde stattgegeben."], ["Die st\xE4rkste Waffe in dieser Stadt ist ein h\xF6flicher, korrekter Brief."]], "questions": [{ "text": "Warum lehnte das Amt den Antrag ab?", "options": [{ "t": "Wegen eines fehlenden Stempels.", "ok": true }, { "t": "Wegen der falschen Adresse.", "ok": false }, { "t": "Wegen des Wetters.", "ok": false }] }, { "text": "Wie endete die Geschichte?", "options": [{ "t": "Dem Widerspruch wurde stattgegeben.", "ok": true }, { "t": "Der Antrag wurde wieder abgelehnt.", "ok": false }, { "t": "Es kam keine Antwort.", "ok": false }] }] }, { "id": 20, "level": "B2", "title": "DIE ENTSCHEIDUNG", "theme": "FINALE / PLUSQUAMPERFEKT", "focus": { "title": "Plusquamperfekt + Passiv der Vergangenheit", "en": "Plusquamperfekt = past before past: hatte gelernt (had learned). Past passive perfect: war evakuiert worden (had been evacuated). The most complex standard German tense construction \u2014 if you read this chapter comfortably, you are at B2." }, "paragraphs": [["Am Ende fand ich die Wahrheit \xFCber die Zone heraus: Dort lebte niemand \u2014 au\xDFer denen, die die Stadt vergessen wollte."], ["Das M\xE4dchen hie\xDF Kara.", "Ihre Familie war vor Jahren evakuiert worden, jedoch ohne Papiere.", "Ohne Papiere existierte sie offiziell nicht; und wer nicht existiert, darf nicht durch das Tor."], ["Ich kannte inzwischen beide Welten: die der Maschinen, die ehrlich versagen, und die der Formulare, die Menschen verschwinden lassen."], ["Also tat ich, was ich gelernt hatte: Ich f\xFCllte Formulare aus.", "Antrag f\xFCr Antrag, Widerspruch f\xFCr Widerspruch, bis Kara eines Tages einen Pass in der Hand hielt."], ["Manche Schlachten gewinnt man mit hei\xDFem \xD6l.", "Die wichtigsten gewinnt man mit Geduld und einem Kugelschreiber."]], "questions": [{ "text": "Warum existierte Kara offiziell nicht?", "options": [{ "t": "Weil ihre Familie ohne Papiere evakuiert worden war.", "ok": true }, { "t": "Weil sie ein Geist war.", "ok": false }, { "t": "Weil sie nie geboren wurde.", "ok": false }] }, { "text": "Wie half der Pilot Kara?", "options": [{ "t": "Er f\xFCllte Formulare aus, bis sie einen Pass bekam.", "ok": true }, { "t": "Er k\xE4mpfte gegen das Amt.", "ok": false }, { "t": "Er flog sie \xFCber die Mauer.", "ok": false }] }] }];
